const body = $json.body || {};
const event = body.event;
const payload = body.payload || {};

if (!event) throw new Error('Missing webhook event');

const docId = payload.id ?? null;
const externalId = payload.externalId ?? null;
const statusFromDocumenso = payload.status ?? null;

// Map Documenso event -> SignatureGate status.
// Keep it simple and stable: completed => signed, cancelled/rejected => cancelled/rejected, others => pending_signature.
let status = null;
if (event === 'document.completed') status = 'signed';
else if (event === 'document.rejected') status = 'rejected';
else if (event === 'document.cancelled') status = 'cancelled';
else if (event === 'document.sent' || event === 'document.signed') status = 'pending_signature';

return [{
  json: {
    event,
    status,
    statusFromDocumenso,
    docId,
    externalId,
    completedAt: payload.completedAt || null
  }
}];
